import sys

def solve_case(n, s, a):
    a.sort()
    for i in range(n - 2):
        ai = a[i]
        if i > 0 and ai == a[i - 1]:
            continue
        if ai + a[i + 1] + a[i + 2] > s:
            break
        if ai + a[n - 2] + a[n - 1] < s:
            continue
        need = s - ai
        lo, hi = i + 1, n - 1
        while lo < hi:
            cur = a[lo] + a[hi]
            if cur == need:
                return "YES"
            if cur < need:
                lo += 1
            else:
                hi -= 1
    return "NO"

def main():
    data = sys.stdin.buffer.read().split()
    pos = 0
    t = int(data[pos]); pos += 1
    out = []
    for _ in range(t):
        n, s = int(data[pos]), int(data[pos + 1]); pos += 2
        a = [int(x) for x in data[pos:pos + n]]; pos += n
        out.append(solve_case(n, s, a))
    sys.stdout.write("\n".join(out) + "\n")

main()
